input.command:
$targets = @(
    "$env:USERPROFILE\Desktop",
    "$env:USERPROFILE\Downloads",
    "$env:USERPROFILE\Documents",
    "$env:TEMP"
)
$results = foreach ($dir in $targets) {
    if (Test-Path $dir) {
        Get-ChildItem $dir -File -Recurse -ErrorAction SilentlyContinue |
            Where-Object { $_.Length -gt 1MB } |
            Group-Object { (Get-FileHash $_.FullName -Algorithm MD5 -ErrorAction SilentlyContinue).Hash } |
            Where-Object { $_.Count -gt 1 }
    }
}
if ($results.Count -eq 0) {
    Write-Output "在桌面/下载/文档/Temp 中未发现大于 1MB 的重复文件（MD5 相同）"
} else {
    $results | ForEach-Object {
        Write-Output "重复 MD5: $($_.Name) ($($_.Count) 个副本, 大小: $([math]::Round($_.Group[0].Length/1MB, 1)) MB)"
        $_.Group.FullName | ForEach-Object { Write-Output "  - $_" }
    }
}

# Clean duplicated .tmp.node files and OneNote log duplicates
$targets = @(
    "$env:TEMP\*.tmp.node"
)
$removedCount = 0
$removedBytes = 0L

# Remove duplicated tmp.node files (leave one as representative, but they're all temp, so all safe to delete)
foreach ($pattern in $targets) {
    $files = Get-ChildItem $pattern -File -ErrorAction SilentlyContinue
    foreach ($f in $files) {
        $removedBytes += $f.Length
        $removedCount++
        Remove-Item $f.FullName -Force -ErrorAction SilentlyContinue
    }
}

# Clean OneNote diagnostics logs in Temp
$oneNoteDiag = "$env:TEMP\Diagnostics\ONENOTE"
if (Test-Path $oneNoteDiag) {
    $oniFiles = Get-ChildItem $oneNoteDiag -Recurse -File -ErrorAction SilentlyContinue
    foreach ($f in $oniFiles) {
        $removedBytes += $f.Length
        $removedCount++
        Remove-Item $f.FullName -Force -ErrorAction SilentlyContinue
    }
}

Write-Output "已删除 $removedCount 个文件, 释放 $([math]::Round($removedBytes/1MB, 1)) MB"

# Scan D drive for duplicate files >1MB (safe areas only: temp, cache, recycle, and non-system user data)
$targetDirs = @(
    "D:\HuaweiMoveData\Users\25789\Desktop",
    "D:\HuaweiMoveData\Users\25789\Downloads",
    "D:\HuaweiMoveData\Users\25789\Documents",
    "D:\HuaweiMoveData\Users\25789\Videos",
    "D:\HuaweiMoveData\Users\25789\Music",
    "D:\HuaweiMoveData\Users\25789\Pictures"
)

$hashGroups = @{}
$totalScanned = 0
$dedupBytes = 0

foreach ($dir in $targetDirs) {
    if (-not (Test-Path $dir)) { continue }
    Write-Progress -Activity "扫描 D 盘重复文件" -Status "正在处理: $dir"
    Get-ChildItem $dir -File -Recurse -ErrorAction SilentlyContinue |
        Where-Object { $_.Length -gt 1MB } |
        ForEach-Object {
            $hash = (Get-FileHash $_.FullName -Algorithm MD5 -ErrorAction SilentlyContinue).Hash
            if ($hash) {
                if (-not $hashGroups.ContainsKey($hash)) {
                    $hashGroups[$hash] = @()
                }
                $hashGroups[$hash] += $_
            }
        }
}

# Report duplicates
$foundAny = $false
foreach ($kv in $hashGroups.GetEnumerator()) {
    if ($kv.Value.Count -gt 1) {
        $foundAny = $true
        $sizeMB = [math]::Round($kv.Value[0].Length / 1MB, 1)
        $totalWasted = [math]::Round(($kv.Value.Count - 1) * $kv.Value[0].Length / 1MB, 1)
        $dedupBytes += ($kv.Value.Count - 1) * $kv.Value[0].Length
        Write-Output "=== 重复 MD5: $($kv.Key) ==="
        Write-Output "大小: $sizeMB MB × $($kv.Value.Count) 次 = 可释放 $totalWasted MB"
        $kv.Value.FullName | ForEach-Object { Write-Output "  $_" }
        Write-Output ""
    }
}

if (-not $foundAny) {
    Write-Output "在 D 盘桌面/下载/文档/视频/音乐/图片中未发现大于 1MB 的重复文件。"
} else {
    $totalHuman = [math]::Round($dedupBytes / 1MB, 1)
    Write-Output "---"
    Write-Output "总计可释放: $totalHuman MB"
}

Remove-Item "D:\HuaweiMoveData\Users\25789\Downloads\KHY-Quant-Setup-8.0.0 (2).exe" -Force -ErrorAction SilentlyContinue
if (-not (Test-Path "D:\HuaweiMoveData\Users\25789\Downloads\KHY-Quant-Setup-8.0.0 (2).exe")) {
    Write-Output "已删除 KHY-Quant-Setup-8.0.0 (2).exe（133.3 MB）"
}

Remove-Item "D:\HuaweiMoveData\Users\25789\Downloads\KHY-Quant-Setup-8.0.0 (2).exe" -Force -ErrorAction SilentlyContinue
if (-not (Test-Path "D:\HuaweiMoveData\Users\25789\Downloads\KHY-Quant-Setup-8.0.0 (2).exe")) {
